import os
import json


class BaiduOCR:
    CONFIG_PATH = os.path.join(os.environ.get("APPDATA", ""), "智能填表助手", "ocr_config.json")

    def __init__(self):
        self.config = self._load_config()

    def _load_config(self):
        if os.path.exists(self.CONFIG_PATH):
            with open(self.CONFIG_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        return {}

    def save_config(self, app_id, api_key, secret_key):
        cfg = {"app_id": app_id, "api_key": api_key, "secret_key": secret_key}
        os.makedirs(os.path.dirname(self.CONFIG_PATH), exist_ok=True)
        with open(self.CONFIG_PATH, "w", encoding="utf-8") as f:
            json.dump(cfg, f)
        self.config = cfg

    def is_configured(self):
        return all(k in self.config for k in ("app_id", "api_key", "secret_key"))

    def recognize(self, image_path):
        if not self.is_configured():
            return "[OCR未配置，请先设置百度OCR API密钥]"
        from aip import AipOcr
        client = AipOcr(self.config["app_id"], self.config["api_key"], self.config["secret_key"])
        with open(image_path, "rb") as f:
            result = client.basicAccurate(f.read())
        return "\n".join(w["words"] for w in result.get("words_result", []))

import os


class DocumentExtractor:
    def extract(self, file_path):
        ext = os.path.splitext(file_path)[1].lower()
        handlers = {
            '.pdf': self.extract_pdf,
            '.docx': self.extract_word,
            '.xlsx': self.extract_excel,
            '.png': self.extract_image, '.jpg': self.extract_image,
            '.jpeg': self.extract_image, '.bmp': self.extract_image,
        }
        handler = handlers.get(ext)
        if handler:
            return handler(file_path)
        return ""

    def extract_pdf(self, path):
        import pdfplumber
        texts = []
        with pdfplumber.open(path) as pdf:
            for page in pdf.pages:
                t = page.extract_text()
                if t:
                    texts.append(t)
                for table in page.extract_tables():
                    for row in table:
                        texts.append(" ".join(cell or "" for cell in row))
        return "\n".join(texts)

    def extract_word(self, path):
        import docx
        doc = docx.Document(path)
        texts = [p.text for p in doc.paragraphs if p.text.strip()]
        for table in doc.tables:
            for row in table.rows:
                texts.append(" ".join(cell.text for cell in row.cells))
        return "\n".join(texts)

    def extract_excel(self, path):
        import openpyxl
        wb = openpyxl.load_workbook(path, read_only=True, data_only=True)
        texts = []
        for ws in wb.worksheets:
            for row in ws.iter_rows(values_only=True):
                vals = [str(c) for c in row if c is not None]
                if vals:
                    texts.append(" ".join(vals))
        wb.close()
        return "\n".join(texts)

    def extract_image(self, path):
        from app.core.ocr_client import BaiduOCR
        ocr = BaiduOCR()
        return ocr.recognize(path)

    def extract_clipboard(self):
        from PyQt5.QtWidgets import QApplication
        clip = QApplication.clipboard()
        return clip.text() or ""

