import re

# 常见法律停用短语
_STOP_PHRASES = {
    "根据", "依照", "本院认为", "经审理查明", "判决如下", "裁定如下",
    "事实和理由", "诉讼请求", "如不服本判决", "上诉于", "审判长", "审判员",
    "书记员", "人民法院", "民事判决书", "民事裁定书", "行政判决书",
}

# 百家姓前100
_SURNAMES = (
    "赵钱孙李周吴郑王冯陈褚卫蒋沈韩杨朱秦尤许何吕施张孔曹严华金魏陶姜"
    "戚谢邹喻柏水窦章云苏潘葛奚范彭郎鲁韦昌马苗凤花方俞任袁柳酆鲍史唐"
    "费廉岑薛雷贺倪汤滕殷罗毕郝邬安常乐于时傅皮卞齐康伍余元卜顾孟平黄"
    "和穆萧尹姚邵湛汪祁毛禹狄米贝明臧计伏成戴谈宋茅庞熊纪舒屈项祝董梁"
    "杜阮蓝闵席季麻强贾路娄危江童颜郭梅盛林刁钟徐邱骆高夏蔡田樊胡凌霍"
    "虞万支柯昝管卢莫经房裘缪干解应宗丁宣贲邓郁单杭洪包诸左石崔吉钮龚"
)
_SURNAME_SET = set(_SURNAMES) | {"欧阳", "司马", "上官", "诸葛", "司徒", "令狐", "皇甫"}

# 正则模式
_ID_CARD = re.compile(r'[1-9]\d{5}(?:19|20)\d{2}(?:0[1-9]|1[0-2])(?:0[1-9]|[12]\d|3[01])\d{3}[\dXx]')
_PHONE = re.compile(r'1[3-9]\d{9}')
_LANDLINE = re.compile(r'0\d{2,3}-?\d{7,8}')
_ROLE_NAME = re.compile(
    r'(原告|被告|第三人|上诉人|被上诉人|申请人|被申请人|申请执行人|被执行人'
    r'|委托(?:诉讼)?代理人|法定代表人|负责人)'
    r'[（(]?[^）)]*?[）)]?[：:\s]*'
    r'([^\s，。；：！？、,.:;!?\n]{2,20})'
)
_COMPANY = re.compile(r'[\u4e00-\u9fff]{2,20}(?:有限公司|股份有限公司|集团|公司|事务所|合伙企业)')
_ADDRESS = re.compile(r'(?:住所地|地址|住址|住)[：:\s]*([^\s，。；！？\n]{4,30})')
_POSTAL = re.compile(r'[1-9]\d{5}(?!\d)')


class LegalFieldExtractor:
    def extract_fields(self, text):
        if not text:
            return []
        fields = []
        # 结构化提取
        for m in _ID_CARD.finditer(text):
            fields.append(m.group())
        for m in _PHONE.finditer(text):
            fields.append(m.group())
        for m in _LANDLINE.finditer(text):
            fields.append(m.group())
        for m in _ROLE_NAME.finditer(text):
            fields.append(m.group(1))  # 角色
            name = m.group(2).strip()
            if name:
                fields.append(name)
        for m in _COMPANY.finditer(text):
            fields.append(m.group())
        for m in _ADDRESS.finditer(text):
            fields.append(m.group(1).strip())
        # 标点分界提取
        segments = re.split(r'[，。；：！？、,.:;!?\n\r\t]+', text)
        for seg in segments:
            seg = seg.strip()
            if 2 <= len(seg) <= 30 and self._is_likely_field(seg):
                fields.append(seg)
        return self._deduplicate(fields)

    def _is_likely_field(self, seg):
        if seg in _STOP_PHRASES:
            return False
        if not re.search(r'[\u4e00-\u9fff]', seg):
            return False
        # 包含数字（可能是证件号、金额等）
        if re.search(r'\d{3,}', seg):
            return True
        # 以姓氏开头且长度2-4（可能是人名）
        if seg[0] in _SURNAME_SET and 2 <= len(seg) <= 4:
            return True
        if seg[:2] in _SURNAME_SET and 3 <= len(seg) <= 5:
            return True
        # 包含地址关键词
        if re.search(r'[省市区县镇村路街道号楼室]', seg):
            return True
        # 包含法律角色关键词
        if re.search(r'原告|被告|代理人|律师|法院|法官', seg):
            return True
        return False

    def _deduplicate(self, fields):
        seen = set()
        result = []
        for f in fields:
            f = f.strip()
            if f and len(f) <= 30 and f not in seen:
                seen.add(f)
                result.append(f)
        return result

from PyQt5.QtWidgets import QWidget, QHBoxLayout, QLabel, QPushButton
from PyQt5.QtCore import pyqtSignal, QTimer, Qt


class FieldSelector(QWidget):
    fill_requested = pyqtSignal(str)

    def __init__(self, parent=None):
        super().__init__(parent)
        self.fields = []
        self.current_index = 0

        layout = QHBoxLayout(self)
        layout.setContentsMargins(10, 10, 10, 10)

        self.label = QLabel("请导入文档或粘贴文本")
        self.label.setObjectName("fieldDisplay")
        self.label.setMinimumHeight(70)
        self.label.setAlignment(Qt.AlignCenter)
        layout.addWidget(self.label, stretch=1)

        self.fill_btn = QPushButton("填 入")
        self.fill_btn.setObjectName("fillButton")
        self.fill_btn.clicked.connect(self._on_fill)
        layout.addWidget(self.fill_btn)

        self.setFocusPolicy(Qt.StrongFocus)

    def set_fields(self, fields):
        self.fields = fields
        self.current_index = 0
        self._update_display()

    def set_index(self, idx):
        if 0 <= idx < len(self.fields):
            self.current_index = idx
            self._update_display()

    def wheelEvent(self, event):
        if not self.fields:
            return
        delta = event.angleDelta().y()
        if delta > 0 and self.current_index > 0:
            self.current_index -= 1
        elif delta < 0 and self.current_index < len(self.fields) - 1:
            self.current_index += 1
        self._update_display()

    def _update_display(self):
        if self.fields:
            self.label.setText(self.fields[self.current_index])
        else:
            self.label.setText("请导入文档或粘贴文本")

    def _on_fill(self):
        if self.fields:
            self.fill_requested.emit(self.fields[self.current_index])

